def hits_iteration(adj_dict, hub_scores, auth_scores):
    new_auth = {node: 0 for node in adj_dict}
    new_hub = {node: 0 for node in adj_dict}

    # Update Authorities
    for node in adj_dict:
        for neighbor, links in adj_dict.items():
            if node in links:
                new_auth[node] += hub_scores[neighbor]

    # Update Hubs
    for node in adj_dict:
        for target in adj_dict[node]:
            new_hub[node] += new_auth[target]

    return new_hub, new_auth

# Graph: H1->A1,A2; H2->A1; A1 (no links)
graph = {'H1': ['A1', 'A2'], 'H2': ['A1'], 'A1': [], 'A2': []}
hubs = {k: 1.0 for k in graph}; auths = {k: 1.0 for k in graph}

for i in range(2):
    hubs, auths = hits_iteration(graph, hubs, auths)
    print(f"Iter {i+1} Auths: {auths}")
